import toast from 'react-hot-toast'
import GoogleSignUp from '../GoogleSignUp'
import { useState } from 'react'
import Logo from '../../Layout/Header/Logo/Logo'
import Loader from '../../Common/Loader'
import axios from "axios";
import { useNavigate } from "react-router-dom";

const SignUp = ({setIsSignInOpen, setIsSignUpOpen}) => {
  const [loading, setLoading] = useState(false)
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault()

    setLoading(true)
    const data = new FormData(e.currentTarget)
    const value = Object.fromEntries(data.entries())
    const finalData = { ...value }

    await axios.post("api/auth/register", finalData)
    .then((res) => {
      toast.success('Successfully registered');
      setLoading(false)
      setIsSignInOpen(true);
      setIsSignUpOpen(false);
    })
    .catch((err) => {
      const message = err.response?.data?.message || err.message || "Failed to registe.";
      console.log(err);
      toast.error(message);
      setLoading(false)
    });
  }

  return (
    <>
      <div className='text-center justify-self-center block'>
        <Logo />
      </div>

      <GoogleSignUp />

      <span className="z-1 relative my-8 block text-center before:content-[''] before:absolute before:h-px before:w-[40%] before:bg-black/20 before:left-0 before:top-3 after:content-[''] after:absolute after:h-px after:w-[40%] after:bg-black/20 after:top-3 after:right-0">
        <span className='text-body-secondary relative z-10 inline-block px-3 text-base text-black'>
          OR
        </span>
      </span>

      <form onSubmit={handleSubmit}>
        <div className='mb-[22px]'>
          <input
            type='text'
            placeholder='Name'
            name='name'
            required
            className='w-full rounded-md border border-solid bg-transparent px-5 py-3 text-base text-dark outline-hidden transition border-gray-200 placeholder:text-black/30 focus:border-[var(--color-primary)] focus-visible:shadow-none text-black'
          />
        </div>
        <div className='mb-[22px]'>
          <input
            type='email'
            placeholder='Email'
            name='email'
            required
            className='w-full rounded-md border border-solid bg-transparent px-5 py-3 text-base text-dark outline-hidden transition border-gray-200 placeholder:text-black/30 focus:border-[var(--color-primary)] focus-visible:shadow-none text-black'
          />
        </div>
        <div className='mb-[22px]'>
          <input
            type='password'
            placeholder='Password'
            name='password'
            required
            className='w-full rounded-md border border-solid bg-transparent px-5 py-3 text-base text-dark outline-hidden transition border-gray-200 placeholder:text-black/30 focus:border-[var(--color-primary)] focus-visible:shadow-none text-black'
          />
        </div>
        <div className='mb-9'>
          <button
            type='submit'
            className='flex w-full items-center text-18 font-medium justify-center rounded-md  text-white bg-[var(--color-primary)] px-5 py-3 text-darkmode transition duration-300 ease-in-out hover:bg-transparent hover:text-[var(--color-primary)] border-[var(--color-primary)] border hover:cursor-pointer'>
            Sign Up {loading && <Loader />}
          </button>
        </div>
      </form>

      <p className='text-body-secondary mb-4 text-black text-base'>
        By creating an account you are agree with our{' '}
        <a href='/#' className='text-[var(--color-primary)] hover:underline'>
          Privacy
        </a>{' '}
        and{' '}
        <a href='/#' className='text-[var(--color-primary)] hover:underline'>
          Policy
        </a>
      </p>

      <p className='text-body-secondary text-black text-base'>
        Already have an account?
        <button onClick={() => {
                setIsSignInOpen(true);
                setIsSignUpOpen(false);
              }} className='pl-2 text-[var(--color-primary)] hover:underline'>
          Sign In
        </button>
      </p>
    </>
  )
}

export default SignUp
